     5→
     6→/**
     7→ * An abstract class whose instances represent templates for creating Python objects. Each
     8→ * APyNode is a generator for a type of APyObj. For instance, a PyIntNode generates
     9→ * PyIntObjs. If this node represents a compound type, e.g. a list, it will hold
    10→ * references to its child node(s).
    11→ *
    12→ * @param <ObjType> the type of Python object generated by this tree
    13→ */
    14→public abstract class APyNode<ObjType extends APyObj> {
    15→
    16→    /**
    17→     * The domain for exhaustive generation.
    18→     */
    19→    protected List<? extends Number> exDomain;
    20→
    21→    /**
    22→     * The domain for random generation.
    23→     */
    24→    protected List<? extends Number> ranDomain;
    25→
    26→    /**
    27→     * The RNG used for random generation.
    28→     */
    29→    protected Random rand = new Random();
    30→
    31→    /**
    32→     * Returns the left child node.
    33→     *
    34→     * @return the left child node
    35→     */
    36→    public APyNode<?> getLeftChild() {
    37→        return null;
    38→    }
    39→
    40→    /**
    41→     * Returns the right child node.
    42→     *
    43→     * @return the right child node
    44→     */
    45→    public APyNode<?> getRightChild() {
    46→        return null;
    47→    }
    48→
    49→    /**
    50→     * Sets the exhaustive domain to the input list of numbers.
    51→     *
    52→     * @param domain the exhaustive domain
    53→     */
    54→    public void setExDomain(List<? extends Number> domain) {
    55→        this.exDomain = domain;
    56→    }
    57→
    58→    /**
    59→     * Returns the exhaustive domain.
    60→     *
    61→     * @return the exhaustive domain
    62→     */
    63→    public List<? extends Number> getExDomain() {
    64→        return this.exDomain;
    65→    }
    66→
    67→    /**
    68→     * Sets the random domain to the input list of numbers.
    69→     *
    70→     * @param domain the random domain
    71→     */
    72→    public void setRanDomain(List<? extends Number> domain) {
    73→        this.ranDomain = domain;
    74→    }
    75→
    76→    /**
    77→     * Returns the random domain.
    78→     *
    79→     * @return the random domain
    80→     */
    81→    public List<? extends Number> getRanDomain() {
    82→        return this.ranDomain;
    83→    }
    84→
    85→    /**
    86→     * Generates all valid PyObjs of type ObjType within the exhaustive domain.
    87→     *
    88→     * @return a set of PyObjs of type ObjType comprising the exhaustive domain
    89→     */
    90→    public abstract Set<ObjType> genExVals();
    91→
    92→    /**
    93→     * Generates a single valid PyObj of type ObjType within the random domain.
    94→     *
    95→     * @return a single PyObj of type ObjType selected from the random domain
    96→     */
    97→    public abstract ObjType genRandVal();
    98→
    99→    /**
   100→     * Makes a random choice from the random domain.
   101→     *
   102→     * @return a random element from the random domain
   103→     */
   104→    protected Number ranDomainChoice() {
   105→        int choice = this.rand.nextInt(this.ranDomain.size());
   106→        return this.ranDomain.get(choice);
   107→    }
   108→
   109→    /**
   110→     * Finds and returns the maximum value in the exhaustive domain.
   111→     *
   112→     * @return the maximum value in the exhaustive domain
   113→     */
   114→    protected int exDomainMax() {
   115→        var maxLength = 0;
   116→        for (Number length : this.exDomain) {
   117→            if (length.intValue() > maxLength) {
   118→                // Found new max
   119→                maxLength = length.intValue();
   120→            }
   121→        }
   122→        return maxLength;
   123→    }
   124→}

