     7→/**
     8→ * A representation of a node for generating PyStringObjs.
     9→ */
    10→public class PyStringNode extends AIterablePyNode<PyStringObj, PyCharObj> {
    11→
    12→    /**
    13→     * The domain of characters from which valid strings can be constructed.
    14→     */
    15→    private final String charDomain;
    16→
    17→    /**
    18→     * Constructor fot a PyStringNode; initializes its character domain.
    19→     *
    20→     * @param charDomain the valid characters for PyStringObjs generated by this node
    21→     */
    22→    public PyStringNode(String charDomain) {
    23→        this.charDomain = charDomain;
    24→    }
    25→
    26→    /**
    27→     * Generates all valid PyStringObjs within the exhaustive domain; begins by generating
    28→     * all valid characters, and then finds all permutations of them of valid length (as
    29→     * constrained by the exhaustive domain).
    30→     *
    31→     * @return a set of PyStringObjs comprising the exhaustive domain
    32→     */
    33→    @Override
    34→    public Set<PyStringObj> genExVals() {
    35→        // Convert charDomain from a String to a list of each individual character
    36→        // in that string
    37→        Set<PyCharObj> innerVals =
    38→                new HashSet<>(new PyStringObj(this.charDomain).getValue());
    39→
    40→        // Get all permutations in the form of a list of lists of characters
    41→        return this.genPerms(this.exDomainMax(), innerVals);
    42→    }
    43→
    44→    /**
    45→     * Helper function for generating a PyStringObj.
    46→     *
    47→     * @param innerVals the elements to be contained by the generated PyStringObj
    48→     * @return a PyStringObj object encapsulating the innerVals
    49→     */
    50→    @Override
    51→    protected PyStringObj genObj(List<PyCharObj> innerVals) {
    52→        return new PyStringObj(innerVals);
    53→    }
    54→
    55→    /**
    56→     * Helper function for generating one random PyCharObj object.
    57→     *
    58→     * @return a randomly-generated object of type PyCharObj from this.charDomain
    59→     */
    60→    @Override
    61→    protected PyCharObj genRandInnerVal() {
    62→        int choice = this.rand.nextInt(this.charDomain.length());
    63→        return new PyCharObj(this.charDomain.charAt(choice));
    64→    }
    65→}

