package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A simple data class representing a parsed configuration file.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    /**
     * Constructor for ConfigFile.
     *
     * @param funcName the name of the function being tested
     * @param nodes    the list of PyNodes for arguments
     * @param numRand  the number of random tests to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the list of PyNodes.
     *
     * @return the list of PyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }

    /**
     * Returns the number of random tests.
     *
     * @return the number of random tests
     */
    public int getNumRand() {
        return this.numRand;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.*;
import java.util.*;

/**
 * Parses a JSON configuration file into a ConfigFile object.
 */
public class ConfigFileParser {

    /**
     * Domain value constraint types used during parsing.
     */
    private enum DomType {
        BOOL,        // values must be 0 or 1
        INT,         // values must be integers
        FLOAT,       // values can be any number (int or double)
        NON_NEG_INT  // values must be non-negative integers (collection sizes, string lengths)
    }

    /**
     * Parses a JSON string into a ConfigFile.
     *
     * @param configStr the JSON string to parse
     * @return the parsed ConfigFile
     * @throws InvalidConfigException if the config is invalid
     */
    public ConfigFile parse(String configStr) throws InvalidConfigException {
        // Parse JSON
        JSONObject json;
        try {
            json = new JSONObject(configStr);
        } catch (JSONException e) {
            throw new InvalidConfigException("Invalid JSON: " + e.getMessage());
        }

        // Validate required fields are present
        requireField(json, "fname");
        requireField(json, "types");
        requireField(json, "exhaustive domain");
        requireField(json, "random domain");
        requireField(json, "num random");

        // Parse and validate fname
        Object fnameObj = json.get("fname");
        if (!(fnameObj instanceof String)) {
            throw new InvalidConfigException("fname must be a string");
        }
        String fname = (String) fnameObj;

        // Parse and validate types array
        Object typesObj = json.get("types");
        if (!(typesObj instanceof JSONArray)) {
            throw new InvalidConfigException("types must be an array");
        }
        List<String> types = toStringList((JSONArray) typesObj, "types");

        // Parse and validate exhaustive domain array
        Object exDomObj = json.get("exhaustive domain");
        if (!(exDomObj instanceof JSONArray)) {
            throw new InvalidConfigException("exhaustive domain must be an array");
        }
        List<String> exDomains = toStringList((JSONArray) exDomObj, "exhaustive domain");

        // Parse and validate random domain array
        Object ranDomObj = json.get("random domain");
        if (!(ranDomObj instanceof JSONArray)) {
            throw new InvalidConfigException("random domain must be an array");
        }
        List<String> ranDomains = toStringList((JSONArray) ranDomObj, "random domain");

        // Parse and validate num random
        Object numRandObj = json.get("num random");
        if (!(numRandObj instanceof Integer)) {
            throw new InvalidConfigException("num random must be an integer");
        }
        int numRand = (Integer) numRandObj;
        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }

        // Validate array lengths match
        if (types.size() != exDomains.size()) {
            throw new InvalidConfigException(
                "types and exhaustive domain have different lengths");
        }
        if (types.size() != ranDomains.size()) {
            throw new InvalidConfigException(
                "types and random domain have different lengths");
        }

        // Parse each type + domain pair into a node
        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < types.size(); i++) {
            APyNode<?> node = parseArg(types.get(i), exDomains.get(i), ranDomains.get(i));
            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    // ==================== FIELD VALIDATION ====================

    private void requireField(JSONObject json, String field) throws InvalidConfigException {
        if (!json.has(field)) {
            throw new InvalidConfigException("Missing required field: " + field);
        }
    }

    private List<String> toStringList(JSONArray arr, String fieldName)
            throws InvalidConfigException {
        List<String> result = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object elem = arr.get(i);
            if (!(elem instanceof String)) {
                throw new InvalidConfigException(
                    fieldName + " must contain only strings");
            }
            result.add((String) elem);
        }
        return result;
    }

    // ==================== TYPE + DOMAIN PARSING ====================

    /**
     * Parses a type string along with its exhaustive and random domain strings,
     * creating and returning an APyNode with all domains set.
     */
    @SuppressWarnings("unchecked")
    private APyNode<?> parseArg(String typeStr, String exDomStr, String ranDomStr)
            throws InvalidConfigException {

        // Check for spaces in type string (never allowed)
        if (typeStr.contains(" ")) {
            throw new InvalidConfigException("Space in type string: " + typeStr);
        }

        // --- Primitive types (exact match) ---

        if (typeStr.equals("bool")) {
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireNoInner(exSplit, "exhaustive domain", typeStr);
            requireNoInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.BOOL);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.BOOL);
            PyBoolNode node = new PyBoolNode();
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.equals("int")) {
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireNoInner(exSplit, "exhaustive domain", typeStr);
            requireNoInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.INT);
            PyIntNode node = new PyIntNode();
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.equals("float")) {
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireNoInner(exSplit, "exhaustive domain", typeStr);
            requireNoInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.FLOAT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.FLOAT);
            PyFloatNode node = new PyFloatNode();
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        // --- Compound types: must end with ')' ---
        if (!typeStr.endsWith(")")) {
            throw new InvalidConfigException("Invalid type: " + typeStr);
        }

        if (typeStr.startsWith("str(")) {
            String charDomain = typeStr.substring(4, typeStr.length() - 1);
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireNoInner(exSplit, "exhaustive domain", typeStr);
            requireNoInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.NON_NEG_INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.NON_NEG_INT);
            PyStringNode node = new PyStringNode(charDomain);
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.startsWith("list(")) {
            String innerTypeStr = typeStr.substring(5, typeStr.length() - 1);
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireInner(exSplit, "exhaustive domain", typeStr);
            requireInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.NON_NEG_INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.NON_NEG_INT);
            APyNode<?> innerNode = parseArg(innerTypeStr, exSplit[1], ranSplit[1]);
            PyListNode node = new PyListNode(innerNode);
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.startsWith("tuple(")) {
            String innerTypeStr = typeStr.substring(6, typeStr.length() - 1);
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireInner(exSplit, "exhaustive domain", typeStr);
            requireInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.NON_NEG_INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.NON_NEG_INT);
            APyNode<?> innerNode = parseArg(innerTypeStr, exSplit[1], ranSplit[1]);
            PyTupleNode node = new PyTupleNode(innerNode);
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.startsWith("set(")) {
            String innerTypeStr = typeStr.substring(4, typeStr.length() - 1);
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireInner(exSplit, "exhaustive domain", typeStr);
            requireInner(ranSplit, "random domain", typeStr);
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.NON_NEG_INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.NON_NEG_INT);
            APyNode<?> innerNode = parseArg(innerTypeStr, exSplit[1], ranSplit[1]);
            PySetNode node = new PySetNode(innerNode);
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        if (typeStr.startsWith("dict(")) {
            String innerTypeStr = typeStr.substring(5, typeStr.length() - 1);

            // Find ':' at depth 0 in type string to split key:val types
            int typeColonIdx = findColonAtDepth0(innerTypeStr);
            if (typeColonIdx < 0) {
                throw new InvalidConfigException(
                    "Missing ':' separator in dict type: " + typeStr);
            }
            String keyTypeStr = innerTypeStr.substring(0, typeColonIdx);
            String valTypeStr = innerTypeStr.substring(typeColonIdx + 1);

            // Split domain strings
            String[] exSplit = splitDomain(exDomStr);
            String[] ranSplit = splitDomain(ranDomStr);
            requireInner(exSplit, "exhaustive domain", typeStr);
            requireInner(ranSplit, "random domain", typeStr);

            // Parse outer (size) domains
            List<Number> exDom = parseSimpleDomain(exSplit[0], DomType.NON_NEG_INT);
            List<Number> ranDom = parseSimpleDomain(ranSplit[0], DomType.NON_NEG_INT);

            // Split inner domains at ':' (depth 0) to get key and val domains
            int exColonIdx = findColonAtDepth0(exSplit[1]);
            int ranColonIdx = findColonAtDepth0(ranSplit[1]);

            if (exColonIdx < 0) {
                throw new InvalidConfigException(
                    "Missing ':' in dict exhaustive domain: " + exDomStr);
            }
            if (ranColonIdx < 0) {
                throw new InvalidConfigException(
                    "Missing ':' in dict random domain: " + ranDomStr);
            }

            String keyExDom = exSplit[1].substring(0, exColonIdx);
            String valExDom = exSplit[1].substring(exColonIdx + 1);
            String keyRanDom = ranSplit[1].substring(0, ranColonIdx);
            String valRanDom = ranSplit[1].substring(ranColonIdx + 1);

            APyNode<?> keyNode = parseArg(keyTypeStr, keyExDom, keyRanDom);
            APyNode<?> valNode = parseArg(valTypeStr, valExDom, valRanDom);

            PyDictNode node = new PyDictNode(keyNode, valNode);
            node.setExDomain(dedup(exDom));
            node.setRanDomain(dedup(ranDom));
            return node;
        }

        throw new InvalidConfigException("Unknown type: " + typeStr);
    }

    // ==================== DOMAIN SPLITTING ====================

    /**
     * Splits a domain string into an outer domain and an optional inner domain.
     * Returns a String[2] where [0] is the outer domain and [1] is the inner
     * domain content (without enclosing parens), or null if there is no inner domain.
     * Throws InvalidConfigException if the structure is malformed (unbalanced parens,
     * or extra characters after the closing paren).
     */
    private String[] splitDomain(String domStr) throws InvalidConfigException {
        int firstParen = domStr.indexOf('(');
        if (firstParen == -1) {
            // No inner domain
            return new String[]{domStr, null};
        }

        // Outer domain is everything before the first '('
        String outerDom = domStr.substring(0, firstParen);

        // The rest starts with '(' and must end with a matching ')'
        String rest = domStr.substring(firstParen);

        // Find the matching closing paren
        int depth = 0;
        int closeIdx = -1;
        for (int i = 0; i < rest.length(); i++) {
            char c = rest.charAt(i);
            if (c == '(') {
                depth++;
            } else if (c == ')') {
                depth--;
                if (depth == 0) {
                    closeIdx = i;
                    break;
                }
            }
        }

        if (closeIdx == -1) {
            throw new InvalidConfigException(
                "Unbalanced parentheses in domain: " + domStr);
        }

        // After the matching ')', there should be nothing
        if (closeIdx != rest.length() - 1) {
            throw new InvalidConfigException(
                "Spurious characters after closing parenthesis in domain: " + domStr);
        }

        // Extract inner content (strip outer parens)
        String innerDom = rest.substring(1, rest.length() - 1);
        return new String[]{outerDom, innerDom};
    }

    private void requireNoInner(String[] split, String domainLabel, String typeStr)
            throws InvalidConfigException {
        if (split[1] != null) {
            throw new InvalidConfigException(
                domainLabel + " has spurious inner domain for type " + typeStr);
        }
    }

    private void requireInner(String[] split, String domainLabel, String typeStr)
            throws InvalidConfigException {
        if (split[1] == null) {
            throw new InvalidConfigException(
                domainLabel + " is missing inner domain for type " + typeStr);
        }
    }

    // ==================== SIMPLE DOMAIN PARSING ====================

    /**
     * Parses a simple domain string (either range "a~b" or explicit list "[v1, v2, ...]")
     * according to the given domain constraint type.
     */
    private List<Number> parseSimpleDomain(String domStr, DomType domType)
            throws InvalidConfigException {
        if (domStr.startsWith("[")) {
            return parseExplicitList(domStr, domType);
        } else {
            return parseRange(domStr, domType);
        }
    }

    /**
     * Parses a range domain "a~b" (inclusive) into a list of integer values.
     */
    private List<Number> parseRange(String domStr, DomType domType)
            throws InvalidConfigException {
        String[] parts = domStr.split("~");
        if (parts.length != 2) {
            throw new InvalidConfigException("Invalid range notation: " + domStr);
        }

        int lower, upper;
        try {
            lower = Integer.parseInt(parts[0]);
            upper = Integer.parseInt(parts[1]);
        } catch (NumberFormatException e) {
            throw new InvalidConfigException(
                "Non-integer value in range: " + domStr);
        }

        if (lower > upper) {
            throw new InvalidConfigException(
                "Lower bound exceeds upper bound in range: " + domStr);
        }

        // Additional constraint validation
        if (domType == DomType.BOOL) {
            if (lower < 0 || upper > 1) {
                throw new InvalidConfigException(
                    "Bool domain value out of range [0,1]: " + domStr);
            }
        } else if (domType == DomType.NON_NEG_INT) {
            if (lower < 0) {
                throw new InvalidConfigException(
                    "Non-negative domain has negative lower bound: " + domStr);
            }
        }

        List<Number> values = new ArrayList<>();
        for (int i = lower; i <= upper; i++) {
            values.add(i);
        }
        return values;
    }

    /**
     * Parses an explicit list domain "[v1, v2, ...]" into a list of values.
     */
    private List<Number> parseExplicitList(String domStr, DomType domType)
            throws InvalidConfigException {
        if (!domStr.endsWith("]")) {
            throw new InvalidConfigException(
                "Explicit list missing closing bracket: " + domStr);
        }

        String inner = domStr.substring(1, domStr.length() - 1);
        if (inner.trim().isEmpty()) {
            throw new InvalidConfigException("Empty explicit list: " + domStr);
        }

        String[] parts = inner.split(",");
        List<Number> values = new ArrayList<>();
        for (String part : parts) {
            String trimmed = part.trim();
            if (trimmed.isEmpty()) {
                throw new InvalidConfigException(
                    "Empty element in explicit list: " + domStr);
            }

            try {
                if (domType == DomType.FLOAT) {
                    values.add(Double.parseDouble(trimmed));
                } else {
                    // Must be an integer (no decimal points allowed)
                    if (trimmed.contains(".")) {
                        throw new InvalidConfigException(
                            "Decimal value in integer domain: " + trimmed);
                    }
                    values.add(Integer.parseInt(trimmed));
                }
            } catch (NumberFormatException e) {
                throw new InvalidConfigException(
                    "Invalid value in explicit list: " + trimmed);
            }
        }

        // Validate values against domain constraint
        for (Number v : values) {
            if (domType == DomType.BOOL) {
                int iv = v.intValue();
                if (iv < 0 || iv > 1) {
                    throw new InvalidConfigException(
                        "Bool domain value out of range [0,1]: " + v);
                }
            } else if (domType == DomType.NON_NEG_INT) {
                if (v.intValue() < 0) {
                    throw new InvalidConfigException(
                        "Negative value in non-negative domain: " + v);
                }
            }
        }

        return values;
    }

    // ==================== HELPERS ====================

    /**
     * Finds the index of the first ':' character at parenthesis depth 0.
     * Returns -1 if not found.
     */
    private int findColonAtDepth0(String s) {
        int depth = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '(') {
                depth++;
            } else if (c == ')') {
                depth--;
            } else if (c == ':' && depth == 0) {
                return i;
            }
        }
        return -1;
    }

    /**
     * Removes duplicate values from a list while preserving insertion order.
     */
    private List<Number> dedup(List<Number> values) {
        Set<Number> seen = new LinkedHashSet<>(values);
        return new ArrayList<>(seen);
    }
}

